const staticData = $getWorkflowStaticData("global");

// Fix #2: null-safe on both fetches, not just LeetCode
const cfData = $("Fetch Codeforces").first()?.json?.result || [];
const lcData = $("Fetch LeetCode").first()?.json?.data?.topTwoContests || [];

const now = Math.floor(Date.now() / 1000);

// Use IST explicitly instead of server-local time
const d = new Date();
const istString = d.toLocaleString("en-US", { timeZone: "Asia/Kolkata" });
const dIST = new Date(istString);
const currentDay = dIST.getDay();
const currentHour = dIST.getHours();

// Build todayStr from IST date, not UTC
const istYear = dIST.getFullYear();
const istMonth = String(dIST.getMonth() + 1).padStart(2, "0");
const istDate = String(dIST.getDate()).padStart(2, "0");
const todayStr = `${istYear}-${istMonth}-${istDate}`;

let message = "";
let send = false;

// Format helper for time remaining
function getTimeRemaining(startTime) {
  const diff = startTime - now;
  const days = Math.floor(diff / (24 * 60 * 60));
  const hours = Math.floor((diff % (24 * 60 * 60)) / (60 * 60));
  if (days === 0 && hours === 0) return "in less than an hour";
  if (days === 0) return `in ${hours} hour${hours > 1 ? "s" : ""}`;
  if (hours === 0) return `in ${days} day${days > 1 ? "s" : ""}`;
  return `in ${days} day${days > 1 ? "s" : ""} and ${hours} hour${hours > 1 ? "s" : ""}`;
}

// Format helper for duration
function getDuration(seconds) {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  if (m === 0) return `${h} hour${h > 1 ? "s" : ""}`;
  return `${h}h ${m}m`;
}

// Helper to get IST date string from epoch seconds
function getIstDateStr(epochSeconds) {
  const dt = new Date(epochSeconds * 1000);
  const ist = dt.toLocaleString("en-US", { timeZone: "Asia/Kolkata" });
  const dIST = new Date(ist);
  return `${dIST.getFullYear()}-${String(dIST.getMonth() + 1).padStart(2, "0")}-${String(dIST.getDate()).padStart(2, "0")}`;
}

// Fix #3: consider ALL upcoming contests per platform, not just the nearest one,
// so a second same-day contest isn't silently dropped.
const cfUpcoming = cfData
  .filter(c => c.phase === "BEFORE" && c.startTimeSeconds >= now)
  .sort((a, b) => a.startTimeSeconds - b.startTimeSeconds);

const lcUpcoming = lcData
  .filter(c => c.startTime >= now)
  .sort((a, b) => a.startTime - b.startTime);

const nextCf = cfUpcoming.length > 0 ? cfUpcoming[0] : null; // still used for weekly overview
const nextLc = lcUpcoming.length > 0 ? lcUpcoming[0] : null;

let oneHourAlerts = [];
let todayAlerts = [];

// Check ALL upcoming Codeforces contests within the relevant windows
for (const cf of cfUpcoming) {
  const diff = cf.startTimeSeconds - now;
  const dur = getDuration(cf.durationSeconds);
  if (diff > 0 && diff <= 75 * 60) {
    oneHourAlerts.push(`*Codeforces:* ${cf.name} (Duration: ${dur})`);
  }
  if (diff > 0 && getIstDateStr(cf.startTimeSeconds) === todayStr && currentHour >= 8) {
    todayAlerts.push(`🔹 *Platform:* Codeforces\n🏆 *Contest:* ${cf.name}\n⏱️ *Starts:* ${getTimeRemaining(cf.startTimeSeconds)}\n⏳ *Duration:* ${dur}`);
  }
}

// Check ALL upcoming LeetCode contests within the relevant windows
for (const lc of lcUpcoming) {
  const diff = lc.startTime - now;
  const dur = getDuration(lc.duration);
  if (diff > 0 && diff <= 75 * 60) {
    oneHourAlerts.push(`*LeetCode:* ${lc.title} (Duration: ${dur})`);
  }
  if (diff > 0 && getIstDateStr(lc.startTime) === todayStr && currentHour >= 8) {
    todayAlerts.push(`🔹 *Platform:* LeetCode\n🏆 *Contest:* ${lc.title}\n⏱️ *Starts:* ${getTimeRemaining(lc.startTime)}\n⏳ *Duration:* ${dur}`);
  }
}

// Fix #1: compute "is this a NEW one-hour alert" up front, so the priority chain
// only takes the one-hour branch when there's actually something new to send.
// Otherwise it stops falling through and silently blocks today/weekly alerts.
const oneHourKey = oneHourAlerts.join(",");
const isNewOneHour = oneHourAlerts.length > 0 && staticData.lastOneHourAlert !== oneHourKey;

if (isNewOneHour) {
  message = "🔥 *CONTEST STARTING IN 1 HOUR!* 🔥\n\n" + oneHourAlerts.join("\n");
  if ($execution.mode !== "manual") { staticData.lastOneHourAlert = oneHourKey; }
  send = true;
}
else if (todayAlerts.length > 0 && staticData.lastContestDay !== todayStr) {
  message = "🌅 *Contests Happening Today!* Good luck:\n\n" + todayAlerts.join("\n\n");
  if ($execution.mode !== "manual") { staticData.lastContestDay = todayStr; }
  send = true;
}
else if ((currentDay === 1 || currentDay === 4) && currentHour >= 18 && staticData.lastWeeklyDay !== todayStr) {
  message = "*📅 Weekly Contest Overview*\n\n";
  if (nextCf) message += `🔹 *Platform:* Codeforces\n🏆 *Contest:* ${nextCf.name}\n⏱️ *Starts:* ${getTimeRemaining(nextCf.startTimeSeconds)}\n⏳ *Duration:* ${getDuration(nextCf.durationSeconds)}\n\n`;
  if (nextLc) message += `🔹 *Platform:* LeetCode\n🏆 *Contest:* ${nextLc.title}\n⏱️ *Starts:* ${getTimeRemaining(nextLc.startTime)}\n⏳ *Duration:* ${getDuration(nextLc.duration)}\n\n`;
  if ($execution.mode !== "manual") { staticData.lastWeeklyDay = todayStr; }
  send = true;
}

if (!send) {
  return []; // Stop workflow silently
}

return [{ json: { message } }];
